import { z } from "zod";

import { MediaType, OtpType, UserRole } from "@/shared/types/auth.types";

export const SIGN_UP_DTO_SCHEMA = z.object({
  password: z.string().min(8),
  firstName: z.string().min(1),
  lastName: z.string().min(1),
  patronymic: z.string().optional(),
  phoneOtpId: z.string().uuid(),
  emailOtpId: z.string().uuid(),
  role: z.nativeEnum(UserRole),
});

export const SEND_OTP_DTO_SCHEMA = z.object({
  email: z.string().email().optional(),
  phone: z.string().optional(),
  type: z.nativeEnum(OtpType),
  mediaType: z.nativeEnum(MediaType),
});

export const VERIFY_OTP_DTO_SCHEMA = SEND_OTP_DTO_SCHEMA.extend({
  otp: z.string().length(6),
});

export const SIGN_IN_DTO_SCHEMA = z.object({
  email: z.string().email(),
  password: z.string().min(1),
});

export const CHANGE_TEMP_PASSWORD_DTO_SCHEMA = z.object({
  email: z.string().email(),
  newPassword: z.string().min(8),
  session: z.string(),
});

export const REFRESH_TOKEN_DTO_SCHEMA = z.object({
  refreshToken: z.string(),
  accessToken: z.string(),
});

export const SIGN_OUT_DTO_SCHEMA = z.object({
  accessToken: z.string(),
});

export const FORGOT_PASSWORD_DTO_SCHEMA = z.object({
  email: z.string().email().optional(),
  phone: z.string().optional(),
  mediaType: z.nativeEnum(MediaType),
});

export const CONFIRM_FORGOT_PASSWORD_DTO_SCHEMA = z.object({
  otpId: z.string().uuid(),
  newPassword: z.string().min(8),
});

export const AUTH_TOKENS_SCHEMA = z.object({
  accessToken: z.string(),
  refreshToken: z.string(),
  idToken: z.string().optional().default(""),
});

export const SIGN_IN_SUCCESS_RESPONSE_SCHEMA = z.object({
  status: z.literal("SUCCESS"),
  payload: AUTH_TOKENS_SCHEMA,
});

export const SIGN_IN_CHALLENGE_RESPONSE_SCHEMA = z.object({
  status: z.literal("CHALLENGE"),
  challengeName: z.literal("NEW_PASSWORD_REQUIRED"),
  session: z.string(),
  challengeParameters: z.record(z.unknown()),
  message: z.string(),
});

export const SIGN_IN_FAILED_RESPONSE_SCHEMA = z.object({
  status: z.literal("FAILED"),
  message: z.string(),
});

export const SIGN_IN_RESPONSE_SCHEMA = z.union([
  SIGN_IN_SUCCESS_RESPONSE_SCHEMA,
  SIGN_IN_CHALLENGE_RESPONSE_SCHEMA,
  SIGN_IN_FAILED_RESPONSE_SCHEMA,
]);

export const SEND_OTP_RESPONSE_SCHEMA = z.object({
  status: z.literal("SUCCESS"),
  types: z.array(z.nativeEnum(OtpType)),
  validity: z.number(),
  resendAfter: z.number(),
  message: z.string(),
  otp: z.string().optional(),
});

export const OTP_ENTITY_SCHEMA = z.object({
  id: z.string().uuid(),
  approved: z.boolean(),
  updatedAt: z.string(),
});

export const FORGOT_PASSWORD_RESPONSE_SCHEMA = z.object({
  status: z.literal("SUCCESS"),
  message: z.string(),
  otp: z.string().optional(),
});

export const CONFIRM_FORGOT_PASSWORD_RESPONSE_SCHEMA = z.object({
  status: z.literal("SUCCESS"),
  message: z.string(),
});

export const REFRESH_TOKEN_RESPONSE_SCHEMA = z.object({
  accessToken: z.string(),
  refreshToken: z.string(),
  idToken: z.string(),
});

export type SignUpDto = z.infer<typeof SIGN_UP_DTO_SCHEMA>;
export type SendOtpDto = z.infer<typeof SEND_OTP_DTO_SCHEMA>;
export type VerifyOtpDto = z.infer<typeof VERIFY_OTP_DTO_SCHEMA>;
export type SignInDto = z.infer<typeof SIGN_IN_DTO_SCHEMA>;
export type ChangeTempPasswordDto = z.infer<
  typeof CHANGE_TEMP_PASSWORD_DTO_SCHEMA
>;
export type RefreshTokenDto = z.infer<typeof REFRESH_TOKEN_DTO_SCHEMA>;
export type SignOutDto = z.infer<typeof SIGN_OUT_DTO_SCHEMA>;
export type ForgotPasswordDto = z.infer<typeof FORGOT_PASSWORD_DTO_SCHEMA>;
export type ConfirmForgotPasswordDto = z.infer<
  typeof CONFIRM_FORGOT_PASSWORD_DTO_SCHEMA
>;

