  "/sign-in",
  "/register",
  "/verify-otp",
  "/create-password",
  "/forgot-password",
  "/request-forgot-password",
  "/reset-password",
  "/change-temp-password",
] as const;

// These auth pages must remain accessible even when the user is authenticated
// (e.g. password reset should work regardless of session state)
export const AUTH_ROUTES_ALWAYS_ACCESSIBLE = [
  "/request-forgot-password",
  "/forgot-password",
  "/reset-password",
] as const;

export type AuthRoute = (typeof AUTH_ROUTES_LIST)[number];

