export function hardPush(url: string): void {
  window.location.href = url;
}

"use client";

import { KycStatus, useKycStatus } from "@/entities/kyc";
import {
  useActiveBuybacks,
  useBuybackRequests,
  useHistoricalBuybacks,
} from "@/shared/api/query-hooks/use-buyback-requests";
import { APP_ROUTES } from "@/shared/config/app-routes";
import { getCdnUrl } from "@/shared/lib/utils/get-cdn-url";
import { ClosedCard } from "@/shared/ui/closed-card";
import { DealCard } from "@/shared/ui/deal-card";
import { Loader } from "@/shared/ui/loader";
import {
  Accordion,
  AccordionContent,
  AccordionItem,
  AccordionTrigger,
} from "@/shared/ui/shadcn/accordion";
import { Separator } from "@/shared/ui/shadcn/separator";
import {
  Table,
  TableBody,
  TableHead,
  TableHeader,
  TableRow,
} from "@/shared/ui/shadcn/table";
import {
  Tabs,
  TabsContent,
  TabsList,
  TabsTrigger,
} from "@/shared/ui/shadcn/tabs";
import { ArrowUpDownIcon, IdCardIcon } from "lucide-react";
import Image from "next/image";
import { useState } from "react";
import { DealsPromoCard } from "./deals-promo-card";

// REDESIGN CHANGES:
// Merged {deal-card.tsx} and {buyback-card.tsx} components => {deal-card.tsx} now handles both types of orders.

// _______________________________________________________________________________

// TODO:
// Verify if images are being correctly fetched from the CDN.
// Implement the account verification status badge/banner.
// Extract the blue promo card into a separate component and refactor/enhance it.
// Create a dedicated page component for closed orders and implement a filter for them.
// Properly handle "Loading" states and implement Skeleton loaders.
// Replace the Lorem Ipsum placeholder text in the accordion.
// Compress/format the mp4 file for the information card and upload it to the CDN.

export default function MyDealsPage() {
  const [tab, setTab] = useState<"active" | "closed">("active");

  const { data: myRequests, isLoading: isLoadingRequests } = useBuybackRequests(
    {
      take: 100,
      order: "DESC",
    }
  );

  const { data: activeBuybacks, isLoading: isLoadingActive } =
    useActiveBuybacks({
      take: 100,
      order: "DESC",
    });
  const { data: historicalBuybacks, isLoading: isLoadingHistory } =
    useHistoricalBuybacks({
      take: 100,
      order: "DESC",
    });

  const isLoadingTotal = isLoadingRequests || isLoadingActive;

  const { data: kycData } = useKycStatus();
  const isVerified = kycData?.status === KycStatus.VERIFIED;

  const activeCount =
    (myRequests?.data?.length || 0) + (activeBuybacks?.data?.length || 0);
  const closedCount = historicalBuybacks?.data?.length || 0;

  const stats = {
    active: {
      count: activeCount,
      label: activeCount === 1 ? "Active Offer" : "Active Offers",
      desc: "Find below your offers being processed, and active buybacks.",
    },
    closed: {
      count: closedCount,
      label: closedCount === 1 ? "Closed Offer" : "Closed Offers",
      desc: "Review your completed transactions and declined offers.",
    },
  };

  const isTabLoading = tab === "active" ? isLoadingTotal : isLoadingHistory;

  return (
    <div className="mx-auto max-w-[1720px] px-4 py-12 min-[1172px]:px-10">
      <Tabs
        className="flex w-full flex-col gap-8"
        onValueChange={(v) => setTab(v as typeof tab)}
        value={tab}
      >
        {/* Хедер */}
        <div className="flex flex-col gap-4 sm:flex-row sm:items-center sm:justify-between">
          <div className="flex items-center justify-between sm:contents">
            <h1 className="font-extralight font-new-serif text-3xl text-foreground">
              My Offers
            </h1>
            {isVerified ? (
              <div className="flex items-center gap-1.5 rounded-[8px] bg-[#E2E8F0] px-2 py-2 font-new-sans text-[#001A8C] text-sm sm:order-last">
                <IdCardIcon size={16} />
                <span>Account Verified</span>
              </div>
            ) : (
              <div className="flex items-center gap-1.5 rounded-[8px] bg-[#FEF3C7] px-2 py-2 font-new-sans text-[#92400E] text-sm sm:order-last">
                <IdCardIcon size={16} />
                <span>Verification Required</span>
              </div>
            )}
          </div>
          <TabsList className="w-full max-sm:mt-2 sm:w-[298px] lg:w-[498px]">
            <TabsTrigger className="flex-1 text-sm" value="active">
              Active
            </TabsTrigger>
            <TabsTrigger className="flex-1 text-sm" value="closed">
              Closed
            </TabsTrigger>
          </TabsList>
        </div>

        <Separator />

        {!isTabLoading && (
          <div className="flex w-full flex-col gap-1.5 font-new-sans text-[16px] transition-all duration-300">
            <h3 className="font-bold">
              {stats[tab].count} {stats[tab].label}
            </h3>
            <p className="font-[400] text-[#44403C]">{stats[tab].desc}</p>
          </div>
        )}

        <TabsContent className="mt-0 outline-none" value="active">
          {isLoadingTotal && (
            <div className="flex items-center justify-center py-20">
              <Loader />
            </div>
          )}

          {!isLoadingTotal && activeCount === 0 && (
            <DealsPromoCard hasActiveDeals={false} isVerified={isVerified} />
          )}

          {!isLoadingTotal && activeCount > 0 && (
            <div className="grid auto-rows-fr grid-cols-1 items-stretch gap-6 lg:grid-cols-2">
              <DealsPromoCard hasActiveDeals={true} isVerified={isVerified} />

              {activeBuybacks?.data?.map((item) => (
                <DealCard
                  amountLabel="Buyback Price"
                  asset={item.asset}
                  expiresAt="15 Days"
                  expiresLabel="Payment due in"
                  href={APP_ROUTES.BUYBACKS.DETAIL(item.id)}
                  imageSrc={getCdnUrl(
                    item.asset.meta?.photos?.main || item.asset.photos[0]
                  )}
                  isBuyback={true}
                  key={item.id}
                  requestId={item.id}
                  status={item.status}
                  type={item.type}
                />
              ))}

              {myRequests?.data?.map((request) => (
                <DealCard
                  amountLabel="Final Item Valuation"
                  asset={request.buyback.asset}
                  expiresAt={new Date(request.createdAt).toLocaleDateString()}
                  expiresLabel="Created"
                  href={APP_ROUTES.BUYBACK_REQUESTS.DETAIL(request.id)}
                  imageSrc={getCdnUrl(
                    request.buyback.asset.meta?.photos?.main ||
                      request.buyback.asset.photos[0]
                  )}
                  isBuyback={false}
                  key={request.id}
                  requestId={request.id}
                  status={request.status}
                  type={request.buyback.type}
                />
              ))}
            </div>
          )}
        </TabsContent>

        <TabsContent className="mt-0 outline-none" value="closed">
          {(() => {
            if (isLoadingHistory) {
              return (
                <div className="flex items-center justify-center py-20">
                  <Loader />
                </div>
              );
            }

            if (historicalBuybacks?.data?.length === 0) {
              return (
                <div className="flex min-h-[300px] w-full flex-col items-center justify-center rounded-xl border border-gray-200 border-dashed bg-[#EEE9E3] px-4 py-12 text-center">
                  <div className="flex h-12 w-12 items-center justify-center">
                    <Image
                      alt="No offers"
                      height={24}
                      src="/new-design-images/icons/box-icon.svg"
                      width={24}
                    />
                  </div>
                  <h3 className="font-bold font-new-sans text-[#A8A29E] text-sm md:text-[16px]">
                    Nothing to see here yet
                  </h3>
                  <p className="font-new-sans text-[#A8A29E] text-sm md:text-[16px]">
                    All your completed, declined or expired offers will appear
                    here.
                  </p>
                </div>
              );
            }

            return (
              <div className="overflow-hidden rounded-xl border border-gray-200 bg-white shadow-sm">
                <div className="border-gray-100 border-b bg-white px-4 py-3 sm:hidden">
                  <span className="font-new-sans text-[#A3A3A3] text-sm">
                    Offers
                  </span>
                </div>

                <Table>
                  <TableHeader className="hidden bg-[#F8F6F4] sm:table-header-group">
                    <TableRow className="border-gray-100 border-b hover:bg-transparent">
                      <TableHead className="h-10 w-[350px] px-4 font-medium text-[#78716C] text-xs">
                        Item
                      </TableHead>
                      <TableHead className="h-10 text-[#78716C] text-xs">
                        <div className="flex items-center gap-1">
                          Offer Type{" "}
                          <ArrowUpDownIcon className="opacity-50" size={12} />
                        </div>
                      </TableHead>
                      <TableHead className="h-10 text-[#78716C] text-xs">
                        <div className="flex items-center gap-1">
                          Closing Date{" "}
                          <ArrowUpDownIcon className="opacity-50" size={12} />
                        </div>
                      </TableHead>
                      <TableHead className="h-10 text-[#78716C] text-xs">
                        <div className="flex items-center gap-1">
                          Indicative Offer Amount{" "}
                          <ArrowUpDownIcon className="opacity-50" size={12} />
                        </div>
                      </TableHead>
                      <TableHead className="h-10 text-[#78716C] text-xs">
                        <div className="flex items-center gap-1">
                          Offer ID{" "}
                          <ArrowUpDownIcon className="opacity-50" size={12} />
                        </div>
                      </TableHead>
                      <TableHead className="h-10 text-[#78716C] text-xs">
                        <div className="flex items-center gap-1">
                          Status{" "}
                          <ArrowUpDownIcon className="opacity-50" size={12} />
                        </div>
                      </TableHead>
                      <TableHead className="h-10 px-4 text-right font-medium text-[#78716C] text-xs">
                        Actions
                      </TableHead>
                    </TableRow>
                  </TableHeader>

                  <TableBody className="block sm:table-row-group">
                    {historicalBuybacks?.data?.map((item) => (
                      <ClosedCard
                        asset={item.asset}
                        href={APP_ROUTES.BUYBACKS.DETAIL(item.id)}
                        imageSrc={getCdnUrl(
                          item.asset.meta?.photos?.main || item.asset.photos[0]
                        )}
                        key={item.id}
                        requestId={item.id}
                        status={item.status || "Settled"}
                        type={
                          item.type === "DIRECT_SALE"
                            ? "Permanent sale"
                            : "Buyback"
                        }
                      />
                    ))}
                  </TableBody>
                </Table>
              </div>
            );
          })()}
        </TabsContent>
      </Tabs>

      <Separator className="my-12" />
      <section className="mt-6 flex flex-col gap-10 lg:mt-20 lg:flex-row lg:items-start lg:gap-20">
        <div className="lg:flex-1">
          <h2 className="!text-4xl lg:!text-[56px] flex flex-col gap-2 font-extralight font-new-serif text-[#1A1A1A] leading-[1.1]">
            <span>Frequently Asked</span>
            <span>Questions</span>
          </h2>
        </div>

        <div className="mb-4 lg:flex-1">
          <Accordion className="flex w-full flex-col" collapsible type="single">
            <AccordionItem
              className="border-b-[hsl(var(--border))]"
              value="item-1"
            >
              <AccordionTrigger className="gap-4 pb-6 text-left font-[400] font-new-sans text-lg hover:no-underline md:py-0 md:pb-6">
                How can I create a sell or buyback offer request?
              </AccordionTrigger>
              <AccordionContent className="pb-6 text-[#60605E] text-[16px] leading-relaxed">
                Lorem ipsum dolor sit amet, consectetur adipiscing elit. Nunc
                vulputate libero et velit interdum, ac aliquet odio mattis.
                Class aptent taciti sociosqu ad litora torquent per conubia
                nostra, per inceptos himenaeos.
              </AccordionContent>
            </AccordionItem>

            <AccordionItem
              className="border-b-[hsl(var(--border))]"
              value="item-2"
            >
              <AccordionTrigger className="gap-4 py-6 text-left font-[400] font-new-sans text-lg hover:no-underline">
                How is the price of my item determined?
              </AccordionTrigger>
              <AccordionContent className="pb-6 text-[#60605E] text-[16px]">
                Our experts analyze current market trends, historical auction
                data, and the condition of your specific asset to provide the
                most accurate valuation.
              </AccordionContent>
            </AccordionItem>

            <AccordionItem
              className="border-b-[hsl(var(--border))]"
              value="item-3"
            >
              <AccordionTrigger className="gap-4 py-6 text-left font-[400] font-new-sans text-lg hover:no-underline">
                How is my item authenticated?
              </AccordionTrigger>
              <AccordionContent className="pb-6 text-[#60605E] text-[16px]">
                Every item undergoes a rigorous multi-stage physical inspection
                by certified specialists before an offer is finalized.
              </AccordionContent>
            </AccordionItem>

            <AccordionItem
              className="border-b-[hsl(var(--border))]"
              value="item-4"
            >
              <AccordionTrigger className="gap-4 py-6 text-left font-[400] font-new-sans text-lg hover:no-underline">
                Is it secure to send my item via courier?
              </AccordionTrigger>
              <AccordionContent className="pb-6 text-[#60605E] text-[16px]">
