"use client";
import { getApi } from "@/shared/api/api";
import { APP_ROUTES } from "@/shared/config/app-routes";
import { getIsClient } from "@/shared/lib/utils/get-is-client";
import type { InternalAxiosRequestConfig } from "axios";
import { isAxiosError } from "axios";
import { signOut, useSession } from "next-auth/react";
import { useRouter } from "next/navigation";
import type { FC } from "react";
import { useCallback, useEffect, useRef } from "react";

const HTTP_STATUS_UNAUTHORIZED = 401;

interface RetryableConfig extends InternalAxiosRequestConfig {
  _retry?: boolean;
}

export const ApiInterceptors: FC = () => {
  const responseInterceptorId = useRef<number | null>(null);
  const isSigningOutRef = useRef(false);
  const router = useRouter();
  const { data: session, update: updateSession } = useSession();

  const handleSignOut = useCallback(async () => {
    if (isSigningOutRef.current) return;
    isSigningOutRef.current = true;
    try {
      await signOut({ redirect: false });
      router.push(APP_ROUTES.AUTH.SIGN_IN);
    } finally {
      isSigningOutRef.current = false;
    }
  }, [router]);

  const responseErrorInterceptor = useCallback(
    async (error: unknown) => {
      if (!isAxiosError(error)) {
        return Promise.reject(error);
      }

      const config = error.config as RetryableConfig | undefined;

      if (
        error?.response?.status === HTTP_STATUS_UNAUTHORIZED &&
        session?.user &&
        config &&
        !config._retry
      ) {
        config._retry = true;

        try {
          // Force NextAuth to re-run the JWT callback, which refreshes
          // the Cognito access token if it has expired.
          const refreshed = await updateSession();

          if (refreshed?.accessToken) {
            config.headers.Authorization = `Bearer ${refreshed.accessToken}`;
            const api = await getApi();
            return await api(config);
          }
        } catch {
          // refresh failed — fall through to sign out
        }

        await handleSignOut();
      }

      return Promise.reject(error);
    },
    [session?.user, updateSession, handleSignOut],
  );

  const setupInterceptors = useCallback(async () => {
    const api = await getApi();

    responseInterceptorId.current = api.interceptors.response.use(
      undefined,
      responseErrorInterceptor,
    );
  }, [responseErrorInterceptor]);

  const clearInterceptors = useCallback(async () => {
    if (!responseInterceptorId.current) {
      return;
    }

    const api = await getApi();

    api.interceptors.response.eject(responseInterceptorId.current);
  }, []);

  useEffect(() => {
    if (!getIsClient()) {
      return;
    }

    setupInterceptors();

    return () => {
      clearInterceptors();
    };
  }, [setupInterceptors, clearInterceptors]);

  return null;
};

