"use client";

import type { AxiosError, AxiosInstance } from "axios";
import { usePathname, useRouter } from "next/navigation";
import { signOut, useSession } from "next-auth/react";
import { useCallback, useEffect, useRef } from "react";

import { mainApi } from "@/shared/api/main-api-instance";
import { APP_ROUTES } from "@/shared/config/app-routes";
import { AUTH_ROUTES_LIST } from "@/shared/config/auth-constants";

export function useAuthInterceptor() {
  const session = useSession();
  const pathname = usePathname();
  const router = useRouter();
  const isProcessingRef = useRef(false);

  const isAuthRoute = AUTH_ROUTES_LIST.some((route) =>
    pathname.startsWith(route),
  );

  const handleSignOut = useCallback(async () => {
    if (isProcessingRef.current) return;

    isProcessingRef.current = true;

    try {
      await signOut({ redirect: false });
      router.push(APP_ROUTES.AUTH.SIGN_IN);
      router.refresh();
    } finally {
      isProcessingRef.current = false;
    }
  }, [router]);

  const onResponseErrorInterceptor = useCallback(
    async (_api: AxiosInstance, error: AxiosError) => {
      if (
        error?.response?.status === 401 &&
        session?.data?.user &&
        !isAuthRoute &&
        !isProcessingRef.current
      ) {
        await handleSignOut();
      }

      return Promise.reject(error);
    },
    [session?.data?.user, isAuthRoute, handleSignOut],
  );

  useEffect(() => {
    const api = mainApi;

    const interceptor = api.interceptors.response.use(
      undefined,
      onResponseErrorInterceptor.bind(null, api),
    );

    return () => {
      api.interceptors.response.eject(interceptor);
    };
  }, [onResponseErrorInterceptor]);
}

